// gradeEmoji maps grades to brand-consistent status emoji.
// 🟢 Certified (A–B), 🟡 Observations (C), 🟠 Probationary (D), 🔴 Decertified (F), ⚪ Expired.
func gradeEmoji(grade string) string {
	switch grade {
	case "A", "A-", "B+", "B":
		return "🟢"
	case "C":
		return "🟡"
	case "D":
		return "🟠"
	case "F":
		return "🔴"
	default:
		return "⚪"
	}
}

